using System;
using System.Collections.Generic;
using System.Drawing;
using System.Linq;
using System.Threading;
using System.Windows.Forms;
using Triggernometry.Core;
using Triggernometry.FFXIV;
using Triggernometry.PluginBridges;
using Triggernometry.UI.CustomControls;
using Triggernometry.UI.Forms;
using static Triggernometry.UI.Forms.GameConfigForm;

// жіЁеҶҢеӣһи°ғ
RealPlugin.Instance.RegisterNamedCallback(VcEntry.Info.ConfigName, new Action<object, string>((_, __) => VcEntry.Start()), null);

public static class VcEntry
{
    enum Territory : uint
    {
        V6a, V6b, V6c, V7a, V7b,
    }

    static Dictionary<int, Territory> _territories = new Dictionary<int, Territory>()
    {
        [1075] = Territory.V6a, // еёҢжӢүзӢ„е“Ҳж°ҙйҒ“
        [1076] = Territory.V6a, // йӣ¶ејҸеёҢжӢүзӢ„е“Ҳж°ҙйҒ“
        [1155] = Territory.V6b, // е…ӯж №еұұ
        [1156] = Territory.V6b, // йӣ¶ејҸе…ӯж №еұұ
        [1179] = Territory.V6c, // йҳҝзҪ—йҳҝзҪ—еІӣ
        [1180] = Territory.V6c, // йӣ¶ејҸйҳҝзҪ—йҳҝзҪ—еІӣ
        [1317] = Territory.V7a, // е•Ҷе®ўеҘҮи°ӯ
    };

    static bool ShouldDisplayTable(int territoryId, Territory territoryOfTable)
    {
        // еҪ“еүҚдёҚеңЁејӮй—»иҝ·е®«еҶ…пјҢжҳҫзӨәжүҖжңүй…ҚзҪ®
        if (!_territories.TryGetValue(territoryId, out Territory currentTerritory))
            return true;
        // еҪ“еүҚеңЁејӮй—»иҝ·е®«еҶ…пјҢд»…жҳҫзӨәеҜ№еә”й…ҚзҪ®
        else
            return currentTerritory == territoryOfTable;
    }

    // й…ҚзҪ®дҝЎжҒҜе®ҡд№ү
    public static ConfigInfo Info = new ConfigInfo("ејӮй—»иҝ·е®«е®қе®қжӨ…", "3.0", "йҳҝжҙӣ", "V&C_cfg");

    public static void RunConfigForm()
    {
        try { _RunConfigForm(); }
        catch (Exception ex)
        {
            MessageBox.Show("й…ҚзҪ®з•ҢйқўиҝҗиЎҢж—¶йҒҮеҲ°й—®йўҳпјҡ\n\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private static void _RunConfigForm()
    {
        var currentTerritoryId = (int)BridgeFFXIV.ZoneID;

        GameConfigForm form = new GameConfigForm(Info);
        form.Shown += (sender, e) => RealPlugin.Instance.InvokeNamedCallback("command", "/e <se.9>");

        BijectDictionary<string, string> cbxItems;
        Option optionCtrl;

        // --- еҖ’еәҸж·»еҠ йҖүйЎ№з»„ ---

        #region й…ҚзҪ®пјҡ7.4 е•Ҷе®ўеҘҮи°ӯ
        if (ShouldDisplayTable(currentTerritoryId, Territory.V7a))
        {
            OptionsTableLayoutPanel table_v7a = form.AddOptionGroup(" 7.4 е•Ҷе®ўеҘҮи°ӯ ");

            form.AddLabel("Boss 1 дёӨж¬ЎеҸҢзӮ№еҗҚжңәеҲ¶пјҡеқҮд»ҘжңәеҲ¶еҲ·ж–°жЁЎејҸзЎ®е®ҡзӣёеҜ№ж–№еҗ‘еҹәеҮҶпјҢиҖҢйқһз»қеҜ№ж–№еҗ‘еҹәеҮҶгҖӮ", table_v7a);

            cbxItems = new BijectDictionary<string, string>(
                 ("", " й»ҳи®ӨпјҡжҢүз…§жӯЈеҢ—йҖҶж—¶й’Ҳ H иҝ‘ иҝң T"),
                 ("0", " ж— и§Ҷй»ҳи®Өз«ҷдҪҚпјҢиҮӘе·ұеҺ»е·ҰдёҠ вҶ–"),
                 ("1", " ж— и§Ҷй»ҳи®Өз«ҷдҪҚпјҢиҮӘе·ұеҺ»е·ҰдёӢ вҶҷ"),
                 ("2", " ж— и§Ҷй»ҳи®Өз«ҷдҪҚпјҢиҮӘе·ұеҺ»еҸідёӢ вҶҳ"),
                 ("3", " ж— и§Ҷй»ҳи®Өз«ҷдҪҚпјҢиҮӘе·ұеҺ»еҸідёҠ вҶ—")
             );
            form.AddOption(new OptionCbx("Boss 1 ејҖеңәжңәеҲ¶иҮӘиә«жүҖеӨ„еӣӣеҲҶд№ӢдёҖеҚҠеңә", "V7a1_dirN4Override", cbxItems, "",
                null), table_v7a);

            cbxItems = new BijectDictionary<string, string>(
                 ("1,2,3,4", " T > H > иҝ‘ > иҝңпјҲH вҶ” иҝ‘жҚўдҪҚпјү"),
                 ("2,1,3,4", " H > T > иҝ‘ > иҝңпјҲT вҶ” иҝ‘жҚўдҪҚпјү"),
                 ("1,2,4,3", " T > H > иҝң > иҝ‘пјҲH вҶ” иҝңжҚўдҪҚпјү"),
                 ("2,1,4,3", " H > T > иҝң > иҝ‘пјҲT вҶ” иҝңжҚўдҪҚпјү")
             );
            form.AddOption(new OptionCbx("Boss 1 зӮ№еҗҚдјҳе…Ҳзә§ / жҚўдҪҚ", "V7a1_pIdxToPrio", cbxItems, "1,2,3,4",
                "дёӨж¬ЎзӮ№еҗҚзҡ„е…Ёйҳҹдјҳе…Ҳзә§пјҢжҲ–зӯүж•Ҳзҡ„жҚўдҪҚйҖ»иҫ‘гҖӮ"), table_v7a);


        }
        #endregion

        #region й…ҚзҪ®пјҡ6.5 Aloalo Island
        if (ShouldDisplayTable(currentTerritoryId, Territory.V6c))
        {
            OptionsTableLayoutPanel table_v6c = form.AddOptionGroup(" 6.5 йҳҝзҪ—йҳҝзҪ—еІӣ ");

            cbxItems = new BijectDictionary<string, string>(
                ("еҚ—еҢ—", " еҚ—еҢ—ејҸпјҲжҺЁиҚҗпјү"),
                ("жҺ’йҳҹ", " жҺ’йҳҹејҸ"),
                ("иһҚеҗҲ", " иһҚеҗҲејҸ")
            );
            form.AddOption(new OptionCbx("Boss 1 ејҖеңәж°ҙжҷ¶жңәеҲ¶ж”»з•ҘйҖүжӢ©", "vc65_1_crStrat", cbxItems, "еҚ—еҢ—",
                "ж”»з•Ҙдёӯзҡ„дёүз§Қз«ҷдҪҚж–№ејҸгҖӮжҜҸз§Қж”»з•ҘдёӢйғҪеҸҜд»ҘжӯЈзЎ®ж’ӯжҠҘиҮӘе·ұеә”иҜҘеҺ»зҡ„дҪҚзҪ®гҖӮ\n\n" +
                "еҚ—еҢ—ејҸпјҡTиҝңеӣәе®ҡеҢ—еҚҠеңәпјҢHиҝ‘еӣәе®ҡеҚ—еҚҠеңәгҖӮ\n" +
                "ејәзғҲжҺЁиҚҗжӯӨж”»з•ҘпјҢе’Ңж–Үжң¬ж’ӯжҠҘе®ҢзҫҺе…је®№гҖӮ\n" +
                "е…Ёйҳҹе®Ңе…ЁдёҚйңҖиҰҒжҖқиҖғпјҢз…§жҠ„з«ҷдҪҚеҚіеҸҜгҖӮ"), table_v6c);
        }
        #endregion

        #region й…ҚзҪ®пјҡ6.4 е…ӯж №еұұ
        if (ShouldDisplayTable(currentTerritoryId, Territory.V6b))
        {
            OptionsTableLayoutPanel table_v6b = form.AddOptionGroup(" 6.4 е…ӯж №еұұ ");

            cbxItems = new BijectDictionary<string, string>(
                ("diagNear", " ж–ңж–№еҗ‘пјҢйқ иҝ‘еңәдёӯ"),
                ("diagFar", " ж–ңж–№еҗ‘пјҢиҙҙи§’иҗҪ"),
                ("vertical", " жӯЈеҚ—еҢ—пјҢиҙҙиҫ№")
            );
            form.AddOption(new OptionCbx("Boss 3 иөӨеёқз©әй—ӘеҲғжӢүзәҝ", "vc64_3_fire", cbxItems, "vertical",
                "Boss 3 жҖЁзҒөзҢӣиҷҺпјҡ\nиөӨеёқз©әй—ӘеҲғпјҲзҒ«зәҝпјүжңәеҲ¶дёӯпјҢиҝһзәҝзӮ№еҗҚеј•еҜјйқўеҗ‘зҡ„дҪҚзҪ®"), table_v6b);
        }
        #endregion

        #region й…ҚзҪ®пјҡ6.2 еёҢжӢүзӢ„е“Ҳж°ҙйҒ“
        if (ShouldDisplayTable(currentTerritoryId, Territory.V6a))
        {
            OptionsTableLayoutPanel table_v6a = form.AddOptionGroup(" 6.2 еёҢжӢүзӢ„е“Ҳж°ҙйҒ“ ");

            cbxItems = new BijectDictionary<string, string>(("0", " зҰҒжӯў"), ("1", " е…Ғи®ё"));
            form.AddOption(new OptionCbx("жҳҜеҗҰе…Ғи®ёжңӘжқҘи§ӮжөӢпјҲйў„жҠҘе®үе…ЁеҢәпјү", "vc62_allowPredict", cbxItems, "0",
                "еңЁд»ҘдёӢжңәеҲ¶дёӯйў„жҠҘе®үе…ЁеҢәпјҡ\n\n В· ж“ҰжӢӯпјҡе·ҰеҸіеҚҠеңә\n В· еҲҡжӯҰзӘҒ/ж—ӢеҮ»пјҡе……иғҪеұӮж•°"), table_v6a);
        }
        #endregion

        #region й…ҚзҪ®пјҡж–Үжң¬йў‘йҒ“
        OptionsTableLayoutPanel tableChannel = form.AddOptionGroup(" ж–Үжң¬йў‘йҒ“ ");
        var cnlPublicItems = new BijectDictionary<string, string>(
            ("", " пјҲзҰҒз”Ёпјү"), ("p", " е°Ҹйҳҹ"), ("e", " й»ҳиҜӯ"), ("fc", " йғЁйҳҹ"),
            ("l1", " йҖҡи®Ҝиҙқ1"), ("l2", " йҖҡи®Ҝиҙқ2"), ("l3", " йҖҡи®Ҝиҙқ3"), ("l4", " йҖҡи®Ҝиҙқ4"),
            ("l5", " йҖҡи®Ҝиҙқ5"), ("l6", " йҖҡи®Ҝиҙқ6"), ("l7", " йҖҡи®Ҝиҙқ7"), ("l8", " йҖҡи®Ҝиҙқ8"),
            ("cwl1", " и·ЁжңҚйҖҡи®Ҝиҙқ1"), ("cwl2", " и·ЁжңҚйҖҡи®Ҝиҙқ2"), ("cwl3", " и·ЁжңҚйҖҡи®Ҝиҙқ3"), ("cwl4", " и·ЁжңҚйҖҡи®Ҝиҙқ4"),
            ("cwl5", " и·ЁжңҚйҖҡи®Ҝиҙқ5"), ("cwl6", " и·ЁжңҚйҖҡи®Ҝиҙқ6"), ("cwl7", " и·ЁжңҚйҖҡи®Ҝиҙқ7"), ("cwl8", " и·ЁжңҚйҖҡи®Ҝиҙқ8")
        );
        var cnlDebugItems = cnlPublicItems.ShallowCopy();
        cnlDebugItems.RemoveKey("p");
        var cnlPrivateItems = cnlDebugItems.ShallowCopy();
        cnlPrivateItems.RemoveKey("");

        form.AddOption(new OptionCbx("е…¬е…ұйў‘йҒ“", "cnlPublic", cnlPublicItems, "e",
            "жң¬йў‘йҒ“з”ЁдәҺж’ӯжҠҘйғЁеҲҶжңәеҲ¶гҖҒзӨәж„ҸеӣҫгҖҒеӨҚзӣҳдҝЎжҒҜзӯүжңәеҲ¶зӣёе…іеҶ…е®№гҖӮ\n\nй»ҳи®Өи®ҫдёәиҮӘе·ұеҸҜи§Ғзҡ„й»ҳиҜӯйў‘йҒ“пјҢ\nеҰӮжңүйңҖиҰҒеҸҜи®ҫдёәе°ҸйҳҹзӯүгҖӮ"), tableChannel);

        form.AddOption(new OptionCbx("дёӘдәәйў‘йҒ“", "cnlPrivate", cnlPrivateItems, "e",
            "жң¬йў‘йҒ“з”ЁдәҺеҸ‘йҖҒд»…еә”иҮӘе·ұеҸҜи§Ғзҡ„зі»з»ҹжҸҗзӨәж¶ҲжҒҜгҖӮ\n\nжң¬йЎ№и®ҫзҪ®дёҚеә”йҖүжӢ©д»»дҪ•е…¶д»–дәәеҸҜи§Ғзҡ„йў‘йҒ“гҖӮ"), tableChannel);

        form.AddOption(new OptionCbx("и°ғиҜ•йў‘йҒ“", "cnlDebug", cnlDebugItems, "",
            "жң¬йў‘йҒ“з”ЁдәҺеҸ‘йҖҒи°ғиҜ•дҝЎжҒҜгҖӮ\n\nеҰӮжһңдҪ еңЁеҸӮдёҺжөӢиҜ•пјҢиҜ·и®ҫзҪ®дёәиҮӘе·ұеҸҜи§Ғзҡ„йў‘йҒ“гҖӮ\n\nеҰӮжһңдҪ дёҚзҹҘйҒ“д»Җд№ҲеҸ«и°ғиҜ•пјҢе°ұдёҚиҰҒејҖеҗҜгҖӮ"), tableChannel);

        form.AddOption(new OptionCbx("еӨҚжҙ»и®°еҪ•йў‘йҒ“пјҲејҖеҸ‘дёӯпјү", "cnlRes", cnlPublicItems, "e",
            "жң¬йў‘йҒ“з”ЁдәҺејӮй—»йҡҫеәҰдёӢйҳҹеҸӢжӯ»дәЎж—¶жҸҗзӨәи°ҒиҝҳжңүеӨҚжҙ»гҖӮ"), tableChannel);
        #endregion

        #region дҪҝз”ЁиҜҙжҳҺ
        OptionsTableLayoutPanel table_desc = form.AddOptionGroup(" дҪҝз”ЁиҜҙжҳҺ ");
        var lbl = form.AddLabel("иӢҘжңүз–‘й—®пјҢиҜ·жҹҘйҳ…жӯӨи§ҰеҸ‘еҷЁеҲҶз»„еҶ…зҡ„дҪҝз”ЁиҜҙжҳҺпјҢе№¶й…ҚеҗҲиҮӘжЈҖжҺ’жҹҘй—®йўҳгҖӮ", table_desc);
        lbl.ForeColor = Color.FromArgb(0x22, 0x66, 0xff);
        #endregion

        #region й…ҚзҪ®пјҡйҳҹе‘ҳйЎәеәҸ
        if (Entity.GetEntities().Count() > 1)
        {
            string[] playerDescriptions = { "еқҰе…Ӣ", "жІ»з–—", "иҝ‘жҲҳ", "иҝңзЁӢ" };
            form.AddPartyGroup(" йҳҹе‘ҳйЎәеәҸ ", new PartyListPanel(playerDescriptions));
        }
        #endregion

        // з»ҹдёҖжё…зҗҶе№¶иҝҗиЎҢ
        Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
        form.Run();
    }

    [STAThread]
    public static void Start()
    {
        try
        {
            Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
            Thread staThread = new Thread(new ThreadStart(RunConfigForm));
            staThread.SetApartmentState(ApartmentState.STA);
            staThread.Start();
        }
        catch (Exception ex)
        {
            MessageBox.Show("з”ЁжҲ·й…ҚзҪ®иЎЁеҚ•иҝҗиЎҢй”ҷиҜҜпјҡ\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Windows.Forms;
using Triggernometry.Core;

List<TreeNode> FindTargetNodes(IEnumerable<TreeNode> nodes, Func<TreeNode, bool> filter)
{
    var result = new List<TreeNode>();
    foreach (var node in nodes)
    {
        if (!node.Checked) continue;

        if (filter(node))
        {
            result.Add(node);
        }
        else if (node.Nodes.Count > 0)
        {
            result.AddRange(FindTargetNodes(node.Nodes.Cast<TreeNode>(), filter));
        }
    }
    return result;
}

var detectName = "ејӮй—»иҝ·е®«е®қе®қжӨ…";
var allNodes = RealPlugin.Instance.ui.treeView1.Nodes.Cast<TreeNode>();
var matchedNodes = FindTargetNodes(allNodes, node => node.Tag is Folder f && f.Name.Contains(detectName));

if (matchedNodes.Count > 1)
{
    MessageBox.Show($"жЈҖжөӢеҲ°еӨҡдёӘ вҖң{detectName}вҖқ еҲҶз»„пјҢдҪ йңҖиҰҒе…ій—ӯиҮід»…жңүдёҖдёӘеҗҜз”ЁгҖӮ", detectName, MessageBoxButtons.OK, MessageBoxIcon.Warning);
}

