using System;
using System.Globalization;
using Triggernometry.Core;
using Triggernometry.Core.Scripting;
void V6c3_зӮёеј№е®үе…ЁеҢә_AdvWm(object o, string s)
{
    int dir10 = int.Parse(ScriptHelper.GetScalarVariable(false, "V6c3_зӮёеј№_dir10").ToString());
    string dОёraw = ScriptHelper.GetScalarVariable(false, "V6c3_зӮёеј№_dОё")?.ToString() ?? "0";
    double dОё = double.Parse(dОёraw, NumberStyles.Float, CultureInfo.InvariantCulture);
    bool isMidSafe = ScriptHelper.GetScalarVariable(false, "V6c3_зӮёеј№_isMidSafe").ToString().Trim() == "1";

    string command;
    if (!isMidSafe)
    {
        command =
        $@"
            action: arc
            center: -200, 0, -200
            Оё: {dir10} * pi/5 - {dОё}
            r: 13.25
            waymarks: 4321DCBA
        ";
        if (dir10 % 2 == 0) // е°Ҹй’қи§’пјҡиҝҮдёӯеҝғ dir10еҒ¶ еҚ—иҫ№105
        {
            command += "dОё: 105В°";
        }
        else // е°Ҹй”җи§’пјҡиҝҮдёӯеҝғ dir10еҘҮ еҚ—иҫ№176
        {
            command += "dОё: 176В°";
        }
    }
    else
    {
        command =
        $@"
            action: place
            center: -200, 0, -200
            Оё: {dir10} * pi/5 - pi - {dОё}
        ";
        if (dir10 % 2 == 0) // еӨ§й’қи§’пјҡдёҚиҝҮдёӯеҝғ dir10еҒ¶
        {
            command +=
            @"
                A: -1.32, -1.81
                B:  1.32, -1.81
                C: -2.80,  2.00
                D:  2.80,  2.00
                1: -5.37,  5.17
                2:  5.37,  5.17
                3: -8.78,  7.43
                4:  8.78,  7.43
            ";
        }
        else // еӨ§й”җи§’пјҡдёҚиҝҮдёӯеҝғ dir10еҘҮ
        {
            command +=
            @"
                A:   0.00,  1.75
                B:   5.31,  1.65
                C:   0.00, -2.25
                D:  -5.31,  1.65
                1:   9.25,  5.49
                2:  10.66,  1.00
                3: -10.66,  1.00
                4:  -9.25,  5.49
            ";
        }
    }

    RealPlugin.Instance.InvokeNamedCallback("AdvWm", command);
}

