using System;
using System.Collections.Generic;
using System.Linq;
using System.Numerics;
using System.Threading.Tasks;
using Triggernometry.Core;
using Triggernometry.FFXIV;
using static Triggernometry.Core.Scripting.ScriptHelper;

// жіЁеҶҢеӣһи°ғ
RealPlugin.Instance.RegisterNamedCallback("V7a2_зҒөеҮ»жіў", (Action<object, string>)V7a2_зҒөеҮ»жіў_Entry.Callback, registrant: "ејӮй—»иҝ·е®«е®қе®қжӨ…");

public static class V7a2_зҒөеҮ»жіў_Entry
{
    
    public static void Callback(object _, string data)
    {
        CustomLog("[зҒөеҮ»жіў] жҺҘж”¶ж•°жҚ®пјҡ" + data);
        // жҜҸиЎҢпјҡ"sid:tid:x:y:h"
        var parts = data
            .Split('\n')
            .Where(line => !string.IsNullOrWhiteSpace(line))
            .Select(line => line.Split(':').Select(s => s.Trim()).ToList())
            .ToList();

        if (parts.Count == 0)
        {
            ErrorLog("[зҒөеҮ»жіў] жІЎжңүдј е…Ҙж•°жҚ®");
            return;
        }
        var remainedBlades = parts.Select(raw => new Blade(raw)).ToList();
        var remainedPlayerIds = GetListVariable(false, "party")?.Values.Select(v => v.ToString()).ToList()
            ?? throw new Exception("[зҒөеҮ»жіў] е°ҸйҳҹеҲ—иЎЁ lvar:party дёҚеӯҳеңЁ");

        // еҗҜеҠЁејӮжӯҘиҪ®иҜўпјҢзӣҙеҲ°е®Ңе…ЁеҢ№й…ҚжҲ–и¶…ж—¶пјҲ10 sпјү
        Task.Run(async () => {
            try
            {
                await PollMatchingAsync(remainedBlades, remainedPlayerIds);
            }
            catch (Exception ex)
            {
                ErrorLog("[зҒөеҮ»жіў] иҪ®иҜўеҢ№й…ҚиҝһзәҝеҸ‘з”ҹејӮеёё: " + ex.Message);
            }
        });
    }

    private static async Task PollMatchingAsync(List<Blade> remainedBlades, List<string> remainedPlayerIds)
    {
        int timeoutMs = 10000; // 10 s и¶…ж—¶
        int intervalMs = 100;   // 0.1 s й—ҙйҡ”
        DateTime startTime = DateTime.Now;

        void Output(Blade blade)
        {
            if (blade.PlayerId == null)
                throw new Exception($"Blade {blade.SourceId} ж— жі•з”ҹжҲҗж—Ҙеҝ—пјҢжңӘеҢ№й…ҚзҺ©е®¶ IDгҖӮ");
            var msg = $"_V7a2_зҒөеҮ»жіў:x:{blade.X}:y:{blade.Y}:h:{blade.Heading}:tid:{blade.PlayerId}";
            RealPlugin.Instance.LogLineQueuer(msg, null, LogEvent.SourceEnum.Log);
            RealPlugin.Instance.ACTEncounterLogHook(msg);
            remainedBlades.Remove(blade);
            remainedPlayerIds.Remove(blade.PlayerId);
        }

        CustomLog("[зҒөеҮ»жіў] ејҖе§ӢејӮжӯҘиҪ®иҜў...");

        while ((DateTime.Now - startTime).TotalMilliseconds < timeoutMs && remainedBlades.Count > 0 && remainedPlayerIds.Count > 0)
        {
            // 1. иӢҘе·Із»Ҹи®°еҪ•дәҶеҲ°зҺ©е®¶зҡ„жҠҳзәҝпјҢзӣҙжҺҘиҫ“еҮә
            var midToPlayer = GetDictVariable(false, "V7a2_зҒөеҮ»жіў_жӢҗtoдәә") ?? new Triggernometry.Core.Variables.VariableDictionary();

            foreach (var blade in remainedBlades.ToList())
            {
                if (!midToPlayer.Values.TryGetValue(blade.MidpointId, out var varPlayerId))
                    continue;

                var playerId = varPlayerId.ToString();
                blade.PlayerId = playerId;
                Output(blade);
            }

            // 2. еү©дҪҷзҡ„еү‘ж°”ж №жҚ®и·қзҰ»еҢ№й…ҚзҺ©е®¶

            if (remainedBlades.Count > 0)
            {
                // жҸҗеүҚеҝ«з…§зҺ©е®¶дҪҚзҪ®пјҢйҒҝе…ҚеҫӘзҺҜеҶ…йҮҚеӨҚиҺ·еҸ–
                var playersPos = remainedPlayerIds
                    .Select(id => Entity.GetEntityByID(id))
                    .Where(e => e.Exist)
                    .ToDictionary(e => e.HexID, e => e.PosXY);

                var bladesMidpointPos = remainedBlades
                    .Select(b => new { Blade = b, Entity = Entity.GetEntityByID(b.MidpointId) })
                    .Where(x => x.Entity.Exist)
                    .ToDictionary(x => x.Blade, x => x.Entity.PosXY);

                bool hasMatchedAny = false;

                // йҒҚеҺҶжҜҸдёҖдёӘеү‘ж°”
                foreach (var blade in remainedBlades.ToList()) // йҒҝе…Қдҝ®ж”№жһҡдёҫзҡ„йӣҶеҗҲ
                {
                    if (!bladesMidpointPos.TryGetValue(blade, out var bPos))
                        continue;

                    // и®Ўз®—иҜҘеү‘ж°”еҲ°жүҖжңүеӯҳжҙ»зҺ©е®¶зҡ„и·қзҰ»е№¶жҺ’еәҸ
                    var sortedDistances = playersPos.Select(p => new
                    {
                        Id = p.Key,
                        Distance = Vector2.Distance(bPos, p.Value)
                    }).OrderBy(d => d.Distance).ToList();

                    if (sortedDistances.Count > 0)
                    {
                        var closest = sortedDistances[0];
                        // еҲӨе®ҡжқЎд»¶пјҡжңҖиҝ‘зҡ„еңЁ 1 зұіеҶ…пјҢжҲ–еҶҚж— еҸҜиғҪзҡ„еҢ№й…ҚпјҲеҸӘжңүдёҖдёӘзҺ©е®¶е’Ңеү‘пјү
                        bool isSingleMatch = sortedDistances.Count == 1 && remainedBlades.Count == 1;
                        bool isClosestNear = isSingleMatch || closest.Distance < 1.0;
                        // еҲӨе®ҡжқЎд»¶пјҡеҰӮжһңжІЎжңүз¬¬дәҢдёӘзҺ©е®¶пјҢжҲ–иҖ…з¬¬дәҢдёӘзҺ©е®¶еңЁ 2 зұіеӨ–
                        bool isOthersFar = sortedDistances.Count == 1 || sortedDistances[1].Distance > 2.0;

                        if (isClosestNear && isOthersFar)
                        {
                            CustomLog($"[зҒөеҮ»жіў] еҢ№й…ҚжҲҗеҠҹ: еү‘ {blade.SourceId} -> зҺ©е®¶ {closest.Id} (и·қзҰ»: {closest.Distance:F2}m)");
                            blade.PlayerId = closest.Id;
                            Output(blade);
                            bladesMidpointPos.Remove(blade);
                            playersPos.Remove(blade.PlayerId);
                            hasMatchedAny = true;
                        }
                        else
                        {
                            var secondText = sortedDistances.Count > 1 ? $"{sortedDistances[1].Distance:F2} m" : "(ж— )";
                            Custom2Log($"[зҒөеҮ»жіў] еҢ№й…ҚдёҚзЎ®е®ҡ: еү‘ {blade.SourceId} жңҖиҝ‘зҺ©е®¶ {closest.Id} {closest.Distance:F2} mпјҢж¬Ўиҝ‘зҺ©е®¶ {secondText}");
                        }
                    }
                }
                if (hasMatchedAny)
                {
                    continue; // еҰӮжһңжң¬иҪ®жңүеҢ№й…ҚжҲҗеҠҹпјҢз«ӢеҲ»йҮҚз®—пјҢеӣ дёәеү©дҪҷеҲ—иЎЁе·Іжӣҙж–°пјҢеҸҜиғҪдҪҝеҺҹжң¬ж— жі•еҢ№й…Қзҡ„еҸҜд»ҘеҢ№й…ҚдәҶ
                }
            }
            await Task.Delay(intervalMs);
        }

        if (remainedBlades.Count > 0 || remainedPlayerIds.Count > 0)
        {
            var elapsedMs = (DateTime.Now - startTime).TotalMilliseconds;
            WarningLog($"[зҒөеҮ»жіў] иҪ®иҜўз»“жқҹ ({elapsedMs / 1000:F2} s) еҗҺд»ҚжңүжңӘеҢ№й…Қе®һдҪ“пјҡ\n" +
                $"еү©дҪҷ blades: {string.Join(", ", remainedBlades.Select(b => b.SourceId))}пјӣ\n" +
                $"еү©дҪҷ playersпјҡ{string.Join(", ", remainedPlayerIds)}");
        }
        
    }

    public class Blade
    {
        public string SourceId { get; set; }
        public string MidpointId { get; set; }
        public string PlayerId { get; set; }
        public string X { get; set; }
        public string Y { get; set; }
        public string Heading { get; set; }
        public Blade(List<string> raw)
        {
            // жҜҸиЎҢпјҡ"sid:tid:x:y:h"
            if (raw.Count != 5)
                throw new Exception("ж•°жҚ®ж јејҸдёҚз¬ҰеҗҲ sid:tid:x:y:hгҖӮж•°жҚ®пјҡ" + string.Join(":", raw));
            SourceId = raw[0];
            MidpointId = raw[1];
            X = raw[2];
            Y = raw[3];
            Heading = raw[4];
        }
    }
}

